#include "ec_sensor.h"
#include <Arduino.h>
#define EC_PIN 34
static float _ec=0,_v=0;static unsigned long _l=0;
void ec_setup(){Serial.println("[ec] OK");}
void ec_loop(){if(millis()-_l<1000)return;_l=millis();int r=0;for(int i=0;i<10;i++)r+=analogRead(EC_PIN);_v=r/10.0*3.3/4095.0;_ec=_v*1000.0;}
float ec_get_value(){return _ec;}
float ec_get_voltage(){return _v;}
